const QUEUES = {
  IMAP_SYNC: 'imap-sync',
  EMAIL_SEND: 'email-send',
  PGP_PROCESS: 'pgp-process',
  CLAMAV_SCAN: 'clamav-scan',
  NOTIFICATION: 'notification',
};

// ------------------------------------------------------------------
