// ------------------------------------------------------------------
// Singleton
// ------------------------------------------------------------------
let _manager: MailConnectionManager | null = null;

export function getMailConnectionManager(): MailConnectionManager {
  if (!_manager) {
    _manager = new MailConnectionManager();
    _manager.start();
  }
  return _manager;
}

export function resetMailConnectionManager(): void {
  if (_manager) {
    void _manager.stop();
    _manager = null;
  }
}

