      `${base}/${rel}.txt`,
    ];

    for (const url of candidates) {
      try {
        const resp = await _safeFetch(url);
        if (resp) {
          const html = await resp.text();
          this.cache.set(route, html);
          return html;
        }
      } catch { /* siguiente candidato */ }
    }

    const providerContent = await Hooks.getContent?.(route);

const resp = await _safeFetch(url);
        if (resp) {
