/* ============================================================
   § 10 — KEYBOARD SHORTCUTS
   ============================================================ */
const KeyboardManager = {
  init() {
    document.addEventListener('keydown', (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') {
        if (e.key === 'Escape') {
          e.target.blur();
          return;
        }
        return;
      }

      switch (e.key) {
        case 'ArrowLeft':
          if (!e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            WikiRouter.back();
          }
          break;
        case 'ArrowRight':
          if (!e.ctrlKey && !e.metaKey) {
            e.preventDefault();
            WikiRouter.forward();
          }
          break;
        case '?':
          if (!e.ctrlKey && !e.metaKey && !e.altKey) {
            WikiUI.openHelp();
          }
          break;
        case 'p':
          if (e.ctrlKey || e.metaKey) {
            e.preventDefault();
            window.print();
          }

