          if (e.ctrlKey || e.metaKey) {
            e.preventDefault();
            window.print();
          }
          break;
      }

      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        const searchInput = $q('#search-input');
        searchInput?.focus();
      }

      if ((e.ctrlKey || e.metaKey) && e.key === 'b') {
        e.preventDefault();
        SidebarManager.toggle();
      }
    });
  },
