  init() {
    const btn = $q('#back-to-top');
    if (!btn) return;

    const onScroll = debounce(() => {
      btn.hidden = window.scrollY < 300;
    }, 100);

    window.addEventListener('scroll', onScroll, { passive: true });
    btn.addEventListener('click', () => {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
  },
};

