// ============================================================================
// Crux-Webmail Frontend — Shared Types
// ============================================================================
// Definiciones centralizadas para el frontend. Se alinea con src/shared/types.ts
// para consistencia del contrato API bidireccional.
// ============================================================================

// ------------------------------------------------------------------
// Auth
// ------------------------------------------------------------------
export interface AuthToken {
  access_token: string;
  refresh_token: string;
  session_id: string;
  expires_in: number;
}

export interface LoginPayload {
  username: string;
  password: string;
  client_fingerprint: string;
  ip: string;
  cert_serial: string;
}

export interface UserProfile {
  user_id: string;
  email: string;
  display_name: string;
  roles: string[];
  mfa_enabled: boolean;
  last_login: string;
  sessions: ActiveSession[];
}

export interface ActiveSession {
  session_id: string;
  created_at: string;
  browser: string;
  ip: string;
  is_current: boolean;
}

// ------------------------------------------------------------------
// Session / Fingerprint
// ------------------------------------------------------------------
export interface ClientFingerprint {
  browser: string;
  os: string;
  screen: string;
  timezone: string;
  languages: string[];
  hash: string;
}

export interface SessionState {
  isAuthenticated: boolean;
  token: string | null;
  refreshToken: string | null;
  sessionId: string | null;

timezone: string;
  languages: string[];
  hash: string;
}

export interface SessionState {
  isAuthenticated: boolean;
  token: string | null;
  refreshToken: string | null;
  sessionId: string | null;
  user: UserProfile | null;
  expiresAt: number;
  fingerprint: ClientFingerprint | null;
}

// ------------------------------------------------------------------
// API Response (unificado — se importa desde shared para el contrato)
// ------------------------------------------------------------------
export interface ApiError {
  status: number;
  code: string;
  message: string;
  details?: Record<string, unknown>;
  correlation_id: string;
}

export interface ApiResponse<T = unknown> {
  data?: T;
  error?: ApiError;
  correlation_id: string;
}

export interface PaginatedResponse<T> {
  items: T[];
  queryId: string;
  newPosition: string | null;
  total?: number;
}

// ------------------------------------------------------------------
// Mail / JMAP
// ------------------------------------------------------------------
export interface Mailbox {
  id: string;
  name: string;
  role?: string;
  subscriptionEnabled: boolean;
  parentId?: string;
  childMailboxes?: string[];
  totalMessages?: number;
  unseenMessages?: number;
}

export interface EmailMessage {
  id: string;
  listIds: string[];
  mailboxId: string;
  subject: string;
  from: EmailAddress[];
  to: EmailAddress[];

unseenMessages?: number;
}

export interface EmailMessage {
  id: string;
  listIds: string[];
  mailboxId: string;
  subject: string;
  from: EmailAddress[];
  to: EmailAddress[];
  cc?: EmailAddress[];
  bcc?: EmailAddress[];
  date: string;
  previewText: string;
  size: number;
  isSeen: boolean;
  isFlagged: boolean;
  isDraft: boolean;
  hasAttachments: boolean;
  headers?: Record<string, string>;
  bodyStructure?: BodyStructure;
  isEncrypted: boolean;
  isSigned: boolean;
  quarantine_status?: 'clean' | 'quarantined' | 'suspicious';
}

export interface EmailAddress {
  name: string;
  email: string;
}

export interface BodyStructure {
  type: string;
  subtype: string;
  params: Record<string, string>;
  description?: string;
  encoding: string;
  md5?: string;
  size: number;
  disposition?: string;
  language?: string[];
  location?: string;
  nestedParts?: BodyStructure[];
}

export interface EmailBodyPart {
  partId: string;
  content: string;
  type: string;
  subtype: string;
  encoding: string;
  filename?: string;
  size: number;
}

export interface AttachmentData {
  name: string;
  mimeType: string;
  data: string; // base64
  size: number;

encoding: string;
  filename?: string;
  size: number;
