// ------------------------------------------------------------------
export function getThemeScript(): string {
  return `
(function(){
  try{
    var s=localStorage.getItem('crux:theme');
    var t=s==='dark'?(s==='dark'?'dark':'light'):s==='system'?(window.matchMedia('(prefers-color-scheme:dark)').matches?'dark':'light'):'light';
