export async function computeFingerprint(): Promise<ClientFingerprint> {
  const browserInfo = parseBrowser(navigator.userAgent);

  const components = [
    browserInfo.name,
    browserInfo.version,
    navigator.userAgent,
    navigator.language,
    navigator.languages?.join(',') ?? '',
    screen.width.toString(),
    screen.height.toString(),
    screen.colorDepth.toString(),
    window.devicePixelRatio?.toString() ?? '1',
    new Date().getTimezoneOffset().toString(),
    navigator.hardwareConcurrency?.toString() ?? '',
    (navigator as any).deviceMemory?.toString() ?? '',
    // Canvas fingerprint
    await getCanvasHash(),
    // WebGL fingerprint
    await getWebGLHash(),
  ];

  const raw = components.join('\u0000');
  const hash = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(raw));
  const hashHex = Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');

  return {
    browser: browserInfo.name,
    os: browserInfo.os,
    screen: `${screen.width}x${screen.height}`,
    timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
    languages: navigator.languages ? [...navigator.languages] : [navigator.language],
    hash: hashHex,
  };
}

