let _env: FrontendEnv | null = null;

export function getEnv(): FrontendEnv {
  if (!_env) {
    _env = resolveEnv();
  }
  return _env;
}

// Eager evaluate at module load
export const env: FrontendEnv = resolveEnv();

export function getEnv(): FrontendEnv {
  if (!_env) {
    _env = resolveEnv();
  }
  return _env;
}

